//block
//noreplace
/**
 * @author Noel Obando
 * @created 2025-12-26
 * @name cmdEmisionIncendioContext
 * @summary Contexto para plantilla contable de emision/cancelacion para el ramo incendios.
 * @param context.id Id de poliza/Id de endoso de cancelacion.
 * @param context.tipo 0: Emision, 1: Endoso de cancelacion., 2: Renovacion, 3: Endoso SA
 */
const { id, tipo = 0 } = context;
const filter = tipo == 0 ? `id=${id}` : 
               [1,3,4].includes(tipo) ? `id IN (SELECT lifePolicyId FROM [Change] WHERE id=${ id })` : 
               `id IN (SELECT lifePolicyId FROM [Anniversary] WHERE id=${ id })`;
doCmd({cmd:'RepoLifePolicy',data:{operation:'GET',noTracking:true, filter, include:['TaxGenerated','Fees','Product', 'Changes.BillDiff']}});
// Policy Data
const [ Policy ] = RepoLifePolicy.outData;

const Titles = {
  0: 'Emisión',
  1: 'Cancelación',
  2: 'Renovación',
  3: 'Endoso Suma Asegurada',
  4: 'Endoso Objeto Asegurado'
},
  Codes = {
  0:'EmisionIncendio',
  1:'CancelacionIncendio',
  2:'RenovacionIncendio',
  3:'EndosoSA',
  4:'EndosoObjetoAsegurado'
};

let primaPorCobrar = 0,
	prima = 0,
	impuestoPrimasIncendio = 0,
	gastoPrimaIncendio = 0,
	cancelacion = false,
	renovacion = false;

const toDecimal = (value) =>
  Number((Math.round((Number(value) || 0) * 100) / 100).toFixed(2));

// Emision/Cancelacion/Renovacion
if([0,1,2].includes(tipo)){
    prima = Policy.coverages;
	impuestoPrimasIncendio = toDecimal((Policy.TaxGenerated || []).reduce((acc, row)=> acc + row.amount,0)),
    gastoPrimaIncendio = toDecimal(prima * 0.02);
    primaPorCobrar = toDecimal(Policy.coverages + impuestoPrimasIncendio);
    cancelacion = tipo == 1;
    renovacion  = tipo == 2;
}else {
    // Endosos.
    const Change = Policy.Changes.find(item => item.id === id);
    if(!Change) throw '@Endoso no encontrado';
    const { BillDiff } = Change;
    if(!BillDiff){
        primaPorCobrar = toDecimal(Policy.coverages + impuestoPrimasIncendio);
        prima = Policy.coverages;
		impuestoPrimasIncendio = toDecimal((Policy.TaxGenerated || []).reduce((acc, row)=> acc + row.amount,0)),
        gastoPrimaIncendio = toDecimal(prima * 0.02);
    } else {
        primaPorCobrar = Math.abs(BillDiff.coverages + BillDiff.tax);
        gastoPrimaIncendio = Math.abs(BillDiff.fee);
		impuestoPrimasIncendio = Math.abs(BillDiff.tax);
		prima = Math.abs(BillDiff.coverages);
        // En caso de devoluciones.
		cancelacion = BillDiff.coverages < 0;
    }
}

// Reinsurance 
doCmd({cmd:'RepoCession',data:{operation:'GET',filter:`lifePolicyId=${ Policy.id } AND overwritten=0`}});
let cessions = RepoCession.outData;
if(tipo == 1)
  cessions = cessions.filter(item => item.premiumType === 'CANCELLATION' )

const reaseguroCedido    = cessions.map(item => Math.abs(toDecimal(item?.premiumRe ?? 0))).reduce((a,b)=>   a + b, 0),
      reaseguroComision  = cessions.map(item => Math.abs(toDecimal(item?.comissionCedant ?? 0))).reduce((a,b)=> a + b, 0),
      reaseguroPorPagar  = reaseguroCedido - reaseguroComision;

const title = Titles[tipo], code = Codes[tipo];

return [{
  primaPorCobrar,
  prima,
  impuestoPrimasIncendio,
  gastoPrimaIncendio,
  daniosPorPagar: gastoPrimaIncendio,
  commisiones: Policy.commissions,
  reservasPorPagar: Policy.commissions,
  reaseguroCedido: Math.abs(reaseguroCedido),
  reaseguroComision: Math.abs(reaseguroComision),
  reaseguroPorPagar: Math.abs(reaseguroPorPagar),
  anioMes: getAnioMes(),
  reference: `${title} Incendio # ${ id }`,
  description: `${title} ${ Policy.Product.name } Póliza # ${ Policy.code }`,
  unique: `TX${ cancelacion ? '-R' : '' }# ${ id }`,
  code: code,
  cancelacion,
  renovacion,
  Policy
}]

function getAnioMes(){
  const  activeDate  = new Date(Policy?.activeDate ?? Policy.start);
  const Meses = {0: 'Ene', 1: 'Feb', 2: 'Mar', 3: 'Abr', 4: 'May', 5: 'Jun', 6: 'Jul', 7: 'Ago', 8: 'Sept', 9: 'Oct', 10: 'Nov', 11: 'Dic'};
  const mes = activeDate.getMonth(),
        anio = activeDate.getFullYear();

  return `${Meses[mes]} ${ anio }`
}
